// Based on "Commodity â€“ Detail" output
const row = items[0].json;

// ---------- Terminals list (supports name-only or name+price) ----------

let rawTerminals = [];

// Prefer terminals_with_price if present, else fallback to terminals_list
const sourceTerminals = row.terminals_with_price ?? row.terminals_list;

if (Array.isArray(sourceTerminals)) {
  rawTerminals = sourceTerminals;
} else if (typeof sourceTerminals === 'string') {
  try {
    rawTerminals = JSON.parse(sourceTerminals);
  } catch (e) {
    rawTerminals = [];
  }
} else if (sourceTerminals && typeof sourceTerminals === 'object') {
  rawTerminals = Object.values(sourceTerminals);
}

// Normalize into { name, price } objects
let terminals = (rawTerminals || [])
  .map(t => {
    if (t && typeof t === 'object') {
      const name =
        (t.terminal_name ?? t.name ?? '').toString().trim();
      const priceRaw =
        t.price ?? t.sell_price ?? t.buy_price ?? null;
      const price = priceRaw !== null ? Number(priceRaw) : null;
      return { name, price };
    }

    const name = String(t || '').trim();
    return { name, price: null };
  })
  .filter(t => t.name.length > 0);

// Sort alphabetically by name (for detailed list)
terminals.sort((a, b) =>
  a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }),
);

const total = Number(row.terminals_total ?? terminals.length) || 0;

// Helper: format price nicely
function formatPrice(p) {
  if (p === null || isNaN(p)) return null;
  return p.toLocaleString('en-US', {
    minimumFractionDigits: 0,
    maximumFractionDigits: 2,
  });
}

// ---------- COMMON HEADER PART ----------

const headerLines = [];

headerLines.push(`# ${row.name}`);
headerLines.push('');

// Use commodity_code if available, fall back to code
const codeValue = row.commodity_code || row.code || 'N/A';

headerLines.push(
  `- **UEX Commodity ID:** ${row.uex_commodity_id || 'N/A'}`,
);
headerLines.push(`- **Code:** ${codeValue}`);
headerLines.push(`- **Category:** ${row.category || 'Unknown'}`);
if (total === 0) {
  headerLines.push(`- **Trade Presence:** No live price data yet`);
} else {
  headerLines.push(`- **Trade Presence:** Seen at ${total} terminals`);
}
headerLines.push('');

// ---------- SUMMARY (LIMITED) VERSION ----------

// Selection rule:
// - If total <= 5 â†’ show all
// - If total > 5 â†’ pick 2 lowest, 2 highest, 1 middle by price

let shownSummary = [];
let suffixSummary = '';

if (total <= 5) {
  // Just use all of them
  shownSummary = [...terminals];
} else {
  // Filter to those with numeric prices for ranking
  const priced = terminals.filter(
    t => t.price !== null && !isNaN(t.price),
  );

  if (priced.length >= 5) {
    // Sort by price ascending
    const byPriceAsc = [...priced].sort(
      (a, b) => a.price - b.price,
    );
    const n = byPriceAsc.length;

    const idxs = [
      0, // lowest
      1, // second lowest
      Math.floor(n / 2), // middle
      n - 2, // second highest
      n - 1, // highest
    ];

    const chosenMap = new Map();

    for (const idx of idxs) {
      const t = byPriceAsc[idx];
      if (!t) continue;
      if (!chosenMap.has(t.name)) {
        chosenMap.set(t.name, t);
      }
    }

    // If we somehow got <5 unique terminals, fill from remaining (alphabetical)
    if (chosenMap.size < 5) {
      for (const t of terminals) {
        if (chosenMap.size >= 5) break;
        if (!chosenMap.has(t.name)) {
          chosenMap.set(t.name, t);
        }
      }
    }

    shownSummary = Array.from(chosenMap.values());
  } else {
    // Not enough priced entries, fallback to first 5 alphabetically
    shownSummary = terminals.slice(0, 5);
  }

  suffixSummary = ` (${shownSummary.length} of ${total})`;
}

// Sort the chosen summary set alphabetically by name for display
shownSummary.sort((a, b) =>
  a.name.localeCompare(b.name, undefined, { sensitivity: 'base' }),
);

const summaryLines = [...headerLines];

summaryLines.push(`## Seen At Terminals${suffixSummary}`);
summaryLines.push('');
summaryLines.push(
  '> _Note: Lists below are unordered and not ranked._',
);
summaryLines.push('');

if (shownSummary.length === 0) {
  summaryLines.push(
    '_No terminals with live sell prices found yet._',
  );
} else {
  for (const t of shownSummary) {
    const priceText = formatPrice(t.price);
    if (priceText) {
      summaryLines.push(`- ${t.name}: ${priceText} aUEC`);
    } else {
      summaryLines.push(`- ${t.name}`);
    }
  }
  if (total > shownSummary.length) {
    summaryLines.push('â€¦ and more');
  }
}

// ---------- DETAILED (FULL) VERSION ----------

const detailedLines = [...headerLines];

detailedLines.push(`## Seen At Terminals`);
detailedLines.push('');
detailedLines.push(
  '> _Detailed view. Lists below are unordered and not ranked._',
);
detailedLines.push('');

if (terminals.length === 0) {
  detailedLines.push(
    '_No terminals with live sell prices found yet._',
  );
} else {
  for (const t of terminals) {
    const priceText = formatPrice(t.price);
    if (priceText) {
      detailedLines.push(`- ${t.name}: ${priceText} aUEC`);
    } else {
      detailedLines.push(`- ${t.name}`);
    }
  }
}

// ---------- SLUG + FILE PATHS ----------

const slug = row.name
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const filePathSummary = `/RAG/KB/commodities/${slug}.md`;
const filePathDetailed = `/RAG/KB/commodities/${slug}_detailed.md`;

return [
  {
    json: {
      commodity_id: row.id,
      slug,
      name: row.name,

      markdown_summary: summaryLines.join('\n'),
      filePath_summary: filePathSummary,

      markdown_detailed: detailedLines.join('\n'),
      filePath_detailed: filePathDetailed,
    },
  },
];

